beginner_examples.query:
const bucket = new GridFSBucket(db);
const fs = require('fs');

const uploadStream = bucket.openUploadStream('image.jpg');
fs.createReadStream('local_image.jpg').pipe(uploadStream);

uploadStream.on('finish', () => {
  console.log('File uploaded');
});

const bucket = new GridFSBucket(db);

const downloadStream = bucket.openDownloadStreamByName('image.jpg');
downloadStream.pipe(fs.createWriteStream('downloaded_image.jpg'));

